// HOW TO RUN:
//   1. Open your target Figma file
//   2. Menu → Plugins → Development → New Plugin
//   3. Choose "Run once" template, paste this entire script, click Run
// ============================================================

const SCREENS = [{"name":"1. Review your trip","data":"","w":375,"h":812},{"name":"2. Choose your seats","data":"","w":375,"h":812},{"name":"3. Add your bags","data":"","w":375,"h":812},{"name":"4. Add your protection \u2605","data":"","w":375,"h":812},{"name":"5. Protection added \u2605","data":"","w":375,"h":812},{"name":"6. Post-checkout recovery","data":"","w":375,"h":812},{"name":"1b. Flight details","data":"","w":375,"h":812},{"name":"1c. Change flight","data":"","w":375,"h":812},{"name":"1d. Review (updated)","data":"","w":375,"h":812},{"name":"1e. Review (price drop on)","data":"","w":375,"h":812},{"name":"1f. Price details (review)","data":"","w":375,"h":812},{"name":"2b. Seat selected ($25)","data":"","w":375,"h":812},{"name":"2c. Price details (no seat)","data":"","w":375,"h":812},{"name":"2d. Seats ICN\u2192SIN","data":"","w":375,"h":812},{"name":"2e. Seat selected ($0)","data":"","w":375,"h":812},{"name":"2c-s. Price details (1 seat)","data":"","w":375,"h":812},{"name":"2c-b. Price details (2 seats)","data":"","w":375,"h":812},{"name":"2d-s. ICN\u2192SIN seat selected","data":"","w":375,"h":812},{"name":"3a. Bags: checked bag added","data":"","w":375,"h":812},{"name":"3b. Price details (seat+bag)","data":"","w":375,"h":812},{"name":"3c. Bags ICN\u2192SIN (no bag)","data":"","w":375,"h":812},{"name":"3d. Bags ICN\u2192SIN (bag added)","data":"","w":375,"h":812},{"name":"4b. Price details (no prot)","data":"","w":375,"h":812},{"name":"4c. Price details (with prot)","data":"","w":375,"h":812},{"name":"1g. Change flight ICN\u2192SIN","data":"","w":375,"h":812},{"name":"1h. Review (ICN\u2192SIN updated)","data":"","w":375,"h":812},{"name":"1j. Review (both Korean Air)","data":"","w":375,"h":812},{"name":"1k. Change flight (KA selected)","data":"","w":375,"h":812},{"name":"1l. Change flight ICN (KA sel)","data":"","w":375,"h":812},{"name":"8b. Order confirmation (KA)","data":"","w":375,"h":812},{"name":"1i. Price details (base fare)","data":"","w":375,"h":812},{"name":"7. Checkout (with protection)","data":"","w":375,"h":812},{"name":"7b. Checkout (no protection)","data":"","w":375,"h":812},{"name":"6b. Add protection confirm","data":"","w":375,"h":812},{"name":"8. Order confirmation","data":"","w":375,"h":812}];

const GAP = 80;
const LABEL_H = 40;

function base64ToUint8Array(b64) {
  const bin = atob(b64);
  const arr = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) arr[i] = bin.charCodeAt(i);
  return arr;
}

async function main() {
  // Create a new page
  const page = figma.createPage();
  page.name = "Loyalty Segment — Insurance Flow";
  figma.currentPage = page;

  let x = 0;

  for (const screen of SCREENS) {
    // Frame
    const frame = figma.createFrame();
    frame.name  = screen.name;
    frame.resize(screen.w, screen.h);
    frame.x = x;
    frame.y = 0;
    frame.cornerRadius = 0;
    frame.clipsContent = true;

    // Image fill
    const img = figma.createImage(base64ToUint8Array(screen.data));
    frame.fills = [{ type: "IMAGE", imageHash: img.hash, scaleMode: "FILL" }];

    // Label text node above each frame
    const lbl = figma.createText();
    await figma.loadFontAsync({ family: "Inter", style: "Bold" });
    lbl.fontName  = { family: "Inter", style: "Bold" };
    lbl.fontSize  = 14;
    lbl.characters = screen.name;
    lbl.fills = [{ type: "SOLID", color: { r: 0.05, g: 0.05, b: 0.11 } }];
    lbl.x = x + screen.w / 2 - lbl.width / 2;
    lbl.y = -LABEL_H;
    page.appendChild(lbl);

    x += screen.w + GAP;
  }

  figma.viewport.scrollAndZoomIntoView(page.children);
  figma.closePlugin("✅  Loyalty Insurance Flow screens added to new page!");
}

main().catch(err => figma.closePlugin("Error: " + err.message));
